import ast

# Get the list of business_refs that received reviews in 2018
reviewed_businesses = set()
for row in env['data_1']:
    # Extract the integer part from businessref_N
    ref = row['business_ref']
    if ref.startswith('businessref_'):
        reviewed_businesses.add(ref.split('_')[1])

# Check attributes for these businesses
count = 0
for row in env['data_2']:
    b_id = row.get('business_id', '')
    if not b_id.startswith('businessid_'):
        continue
    b_num = b_id.split('_')[1]

    if b_num in reviewed_businesses:
        attrs = row.get('attributes')
        if not attrs:
            continue

        has_parking = False

        # Check BikeParking
        bike_parking = attrs.get('BikeParking')
        if bike_parking == 'True':
            has_parking = True

        # Check BusinessParking
        business_parking = attrs.get('BusinessParking')
        if business_parking and business_parking != 'None':
            try:
                # It's a string representation of a dict
                if isinstance(business_parking, str):
                    # Replace u' with ' for ast.literal_eval
                    bp_str = business_parking.replace("u'", "'")
                    bp_dict = ast.literal_eval(bp_str)
                else:
                    bp_dict = business_parking

                if isinstance(bp_dict, dict):
                    if any(val is True for val in bp_dict.values()):
                        has_parking = True
            except Exception as e:
                pass

        if has_parking:
            count += 1

print(f"Number of businesses: {count}")

